#include <string>

extern "C" {
#include "esp_log.h"
#include "esp_partition.h"
#include "spi_flash_mmap.h"
}

#define TAG "Assets"

struct mmap_assets_table {
    char asset_name[32];
    uint32_t asset_offset;
    uint32_t asset_size;
};

struct Asset {
    size_t size;
    size_t offset;
};

class Assets {
private:
    const esp_partition_t* partition_;
    const char* mmap_root_;
    spi_flash_mmap_handle_t mmap_handle_;
    std::map<std::string, Asset> assets_;

public:
    Assets() : partition_(nullptr), mmap_root_(nullptr), mmap_handle_(0) {
        // Step 1: Find the "assets" partition
        partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_ANY, ESP_PARTITION_SUBTYPE_ANY, "assets");
        if (partition_ == nullptr) {
            ESP_LOGI(TAG, "No assets partition found");
            return;
        }

        // Step 2: Check available flash pages before mapping
        int free_pages = spi_flash_mmap_get_free_pages(SPI_FLASH_MMAP_DATA);
        uint32_t storage_size = free_pages * 64 * 1024;

        // Step 3: Map the partition into memory
        esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, ESP_PARTITION_MMAP_DATA, (const void**)&mmap_root_, &mmap_handle_);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mmap assets partition: %s", esp_err_to_name(err));
            return;
        }

        // Step 4: Validate magic number at start
        if (mmap_root_[0] != 'A' || mmap_root_[1] != 'S') {
            ESP_LOGE(TAG, "Invalid magic number in assets partition");
            esp_partition_munmap(mmap_handle_);
            mmap_handle_ = 0;
            mmap_root_ = nullptr;
            return;
        }

        // Step 5: Read header fields
        uint32_t stored_files = *(uint32_t*)(mmap_root_ + 2);
        uint32_t stored_len = *(uint32_t*)(mmap_root_ + 6);
        uint32_t stored_chksum = *(uint32_t*)(mmap_root_ + 10);

        // Step 6: Verify checksum
        auto start_time = esp_timer_get_time();
        uint32_t calculated_checksum = 0;
        for (uint32_t i = 0; i < stored_len; ++i) {
            calculated_checksum += static_cast<uint8_t>(mmap_root_[12 + i]);
        }
        calculated_checksum &= 0xFFFF;
        auto end_time = esp_timer_get_time();

        ESP_LOGI(TAG, "Checksum calculation took %lld ms", (end_time - start_time) / 1000);

        if (calculated_checksum != stored_chksum) {
            ESP_LOGE(TAG, "Calculated checksum (0x%lx) does not match stored checksum (0x%lx)", calculated_checksum, stored_chksum);
            esp_partition_munmap(mmap_handle_);
            mmap_handle_ = 0;
            mmap_root_ = nullptr;
            return;
        }

        // Step 7: Parse asset table
        for (uint32_t i = 0; i < stored_files; ++i) {
            const auto* item = reinterpret_cast<const mmap_assets_table*>(mmap_root_ + 12 + i * sizeof(mmap_assets_table));
            std::string name(item->asset_name);
            Asset asset{
                .size = static_cast<size_t>(item->asset_size),
                .offset = static_cast<size_t>(12 + sizeof(mmap_assets_table) * stored_files + item->asset_offset)
            };
            assets_[name] = asset;
        }

        ESP_LOGI(TAG, "Successfully loaded %lu assets", assets_.size());
    }
};

