const char* g_mapped_partition_address = nullptr;
esp_partition_mmap_handle_t g_mmap_handle = 0;

esp_err_t InitializePartition() {
    // Step 1: Find the partition
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA,
        ESP_PARTITION_SUBTYPE_DATA_UNDEFINED,
        "assets"
    );

    if (partition == nullptr) {
        return ESP_ERR_NOT_FOUND;
    }

    // Step 2: Verify the partition
    partition = esp_partition_verify(partition);
    if (partition == nullptr) {
        return ESP_ERR_INVALID_ARG;
    }

    // Step 3: Map the partition into memory
    esp_err_t err = esp_partition_mmap(
        partition,
        0,
        partition->size,
        ESP_PARTITION_MMAP_DATA,
        (const void**)&g_mapped_partition_address,
        &g_mmap_handle
    );

    if (err != ESP_OK) {
        return err;
    }

    // Optional Step 4: Validate checksum (example uses CRC32)
