    esp_err_t err = esp_partition_erase_range(partition, 0, partition->size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        http->Close();
        return false;
    }

    // Step 5: Begin reading and writing loop
    const size_t BUFFER_SIZE = 4096;
    uint8_t buffer[BUFFER_SIZE];
    size_t total_read = 0;
    size_t offset = 0;
    uint32_t last_progress = 0;

    TickType_t start_time = xTaskGetTickCount();

    while (total_read < content_length) {
        int ret = http->Read(buffer, sizeof(buffer));
        if (ret < 0) {
            ESP_LOGE(TAG, "Failed to read HTTP data: %d", ret);
            http->Close();
            return false;
        }

        // Write to flash partition
        err = esp_partition_write(partition, offset, buffer, ret);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to partition at offset %d: %s", offset, esp_err_to_name(err));
            http->Close();
            return false;
        }

        total_read += ret;
        offset += ret;

        // Compute progress and call callback
        uint32_t progress = (total_read * 100) / content_length;
        if (progress != last_progress) {
            last_progress = progress;

            TickType_t elapsed_ticks = xTaskGetTickCount() - start_time;
            size_t avg_speed_bps = (elapsed_ticks > 0) ? (total_read * configTICK_RATE_HZ) / elapsed_ticks : 0;

            if (progress_callback) {
                progress_callback(static_cast<int>(progress), avg_speed_bps);
            }
