    char* verify_buffer = reinterpret_cast<char*>(malloc(content_length));
    if (!verify_buffer) {
        ESP_LOGE(TAG, "Memory allocation failed for verification buffer.");
        return false;
    }

    err = esp_partition_read(partition, 0, verify_buffer, content_length);
    if (err != ESP_OK) {
        free(verify_buffer);
        ESP_LOGE(TAG, "Failed to read back partition for checksum: %s", esp_err_to_name(err));
        return false;
    }

    uint32_t computed_checksum = CalculateChecksum(verify_buffer, content_length);
    free(verify_buffer);

