    // Perform the actual state update
    current_state_.store(new_state);

    // Make a copy of the listeners to notify outside the lock
    std::vector<StateCallback> callbacks_copy;
    callbacks_copy.reserve(listeners_.size());
    for (const auto& [id, cb] : listeners_)
    {
        callbacks_copy.push_back(cb);
    }

    // Unlock before notifying to avoid potential deadlocks
    lock.unlock();

    // Notify all listeners of the state change
    for (const auto& cb : callbacks_copy)
    {
        cb(old_state, new_state);
    }

    return true;
