    // Step 2: Setup HTTP Client
    auto &board = Board::GetInstance();
    auto network = board.GetNetwork();
    if (!network) {
        ESP_LOGE(TAG, "Network not initialized");
        return false;
    }

    auto http = network->CreateHttp(0);
    if (!http) {
        ESP_LOGE(TAG, "Failed to create HTTP client");
        return false;
    }

    auto user_agent = SystemInfo::GetUserAgent();
    http->SetHeader("Device-Id", SystemInfo::GetMacAddress().c_str());
    http->SetHeader("Client-Id", board.GetUuid());
    http->SetHeader("User-Agent", user_agent.c_str());
    http->SetHeader("Accept-Language", Lang::CODE);
    http->SetHeader("Content-Type", "application/json");

    // Step 3: Send GET Request
    std::string response_body;
    int status_code = http->Get(ota_url, response_body);

    if (status_code != 200) {
        ESP_LOGE(TAG, "HTTP GET failed with status code: %d", status_code);
        return false;
    }

    ESP_LOGI(TAG, "Received response: %s", response_body.c_str());

    // Step 4: Parse JSON Response
    cJSON *json = cJSON_Parse(response_body.c_str());
    if (!json) {
