        return false;
    }

    const char *latest_version_str = cJSON_GetObjectItemCaseSensitive(json, "version")->valuestring;
    if (!latest_version_str) {
        ESP_LOGE(TAG, "Missing 'version' in response");
        cJSON_Delete(json);
        return false;
    }

