    int content_length = http->GetContentLength();
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Invalid content length received");
        http->Close();
        return;
    }

    // Step 2: Prepare OTA partition for writing
    const esp_partition_t* partition = esp_ota_get_next_update_partition(NULL);
    if (!partition) {
        ESP_LOGE(TAG, "Failed to get next OTA partition");
        http->Close();
        return;
    }

    esp_ota_handle_t ota_handle;
    err = esp_ota_begin(partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to begin OTA, error=0x%x", err);
        http->Close();
        return;
    }

    // Step 3: Start downloading and flashing
    uint8_t buffer[1024];
    int total_read = 0;
    auto start_time = std::chrono::steady_clock::now();

    while (true) {
        int read_len = http->Read(buffer, sizeof(buffer));
        if (read_len < 0) {
            ESP_LOGE(TAG, "Error reading HTTP stream");
            break;
        } else if (read_len == 0) {
            // EOF
            break;
        }

        err = esp_ota_write(ota_handle, buffer, read_len);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write OTA data, error=0x%x", err);
            break;
        }

        total_read += read_len;

        // Report progress every 1KB or so
        if (total_read % 1024 == 0 || total_read == content_length) {
            int progress = static_cast<int>((static_cast<float>(total_read) / content_length) * 100);

            auto now = std::chrono::steady_clock::now();
            auto duration = std::chrono::duration_cast<std::chrono::milliseconds>(now - start_time).count();
            size_t speed = (duration > 0) ? (total_read * 1000ULL / duration) : 0;

            callback(progress, speed);
        }
    }

    http->Close();

    if (total_read != content_length) {
        ESP_LOGE(TAG, "Incomplete download: expected=%d, actual=%d", content_length, total_read);
        esp_ota_end(ota_handle);
        return;
    }

    err = esp_ota_end(ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to end OTA, error=0x%x", err);
        return;
    }

    err = esp_ota_set_boot_partition(partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set boot partition, error=0x%x", err);
        return;
    }

    ESP_LOGI(TAG, "OTA upgrade complete. Rebooting...");
    callback(100, 0); // Final call at 100%
    esp_restart();
}

