std::vector<int> ParseVersion(const std::string& version) {
    std::vector<int> result;
    size_t start = 0;
    size_t end = 0;

    while (end <= version.length()) {
        if (end == version.length() || version[end] == '.') {
            std::string part = version.substr(start, end - start);
