void SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait)
{
    // Step 1: Determine the number of tasks by calling with NULL buffer
    volatile UBaseType_t uxArraySize = uxTaskGetSystemState(NULL, 0, NULL);
    if (uxArraySize == 0) {
        ESP_LOGE(TAG, "Failed to retrieve task state (first call)");
        return;
    }

    // Step 2: Allocate memory for both snapshots
    TaskStatus_t *pxTaskStatusArray1 = (TaskStatus_t *)malloc(uxArraySize * sizeof(TaskStatus_t));
    TaskStatus_t *pxTaskStatusArray2 = (TaskStatus_t *)malloc(uxArraySize * sizeof(TaskStatus_t));

    if (pxTaskStatusArray1 == NULL || pxTaskStatusArray2 == NULL) {
        ESP_LOGE(TAG, "Memory allocation failed");
        free(pxTaskStatusArray1);
        free(pxTaskStatusArray2);
        return;
    }

    uint32_t ulTotalRunTime1, ulTotalRunTime2;

    // Step 3: Capture first snapshot
    UBaseType_t uxCurrentArraySize1 = uxTaskGetSystemState(pxTaskStatusArray1, uxArraySize, &ulTotalRunTime1);
    if (uxCurrentArraySize1 == 0) {
        ESP_LOGE(TAG, "Failed to capture first task state snapshot");
        free(pxTaskStatusArray1);
        free(pxTaskStatusArray2);
        return;
    }

    // Step 4: Delay for measurement period
    vTaskDelay(xTicksToWait);

    // Step 5: Capture second snapshot
    UBaseType_t uxCurrentArraySize2 = uxTaskGetSystemState(pxTaskStatusArray2, uxArraySize, &ulTotalRunTime2);
    if (uxCurrentArraySize2 == 0) {
        ESP_LOGE(TAG, "Failed to capture second task state snapshot");
        free(pxTaskStatusArray1);
        free(pxTaskStatusArray2);
        return;
    }

    // Helper lambda to find task in array
    auto TaskExistsInArray = [](TaskHandle_t handle, TaskStatus_t* array, UBaseType_t size) -> bool {
        for (UBaseType_t i = 0; i < size; ++i) {
            if (array[i].xHandle == handle)
                return true;
        }
        return false;
    };

    // Step 6: Compute and print CPU usage for matching tasks
    uint32_t ulTotalRunTimeDiff = ulTotalRunTime2 - ulTotalRunTime1;
    if (ulTotalRunTimeDiff == 0) {
        ESP_LOGW(TAG, "No measurable time difference between snapshots.");
        free(pxTaskStatusArray1);
        free(pxTaskStatusArray2);
        return;
    }

    for (UBaseType_t i = 0; i < uxCurrentArraySize1; ++i) {
        TaskHandle_t hTask = pxTaskStatusArray1[i].xHandle;
        const char* pcName = pxTaskStatusArray1[i].pcTaskName;

        // Find corresponding entry in second snapshot
        TaskStatus_t* pSecondEntry = nullptr;
        for (UBaseType_t j = 0; j < uxCurrentArraySize2; ++j) {
            if (pxTaskStatusArray2[j].xHandle == hTask) {
                pSecondEntry = &pxTaskStatusArray2[j];
                break;
            }
        }

        if (pSecondEntry != nullptr) {
            uint32_t ulRunTimeDiff = pSecondEntry->ulRunTimeCounter - pxTaskStatusArray1[i].ulRunTimeCounter;
            float fCpuPercent = ((float)ulRunTimeDiff / ulTotalRunTimeDiff) * 100.0f;
            ESP_LOGI(TAG, "Task '%s' CPU Usage: %.2f%%", pcName, fCpuPercent);
        } else {
            ESP_LOGW(TAG, "Task '%s' was deleted during measurement", pcName);
        }
    }

    // Step 7: Check for newly created tasks
    for (UBaseType_t i = 0; i < uxCurrentArraySize2; ++i) {
        TaskHandle_t hTask = pxTaskStatusArray2[i].xHandle;
        if (!TaskExistsInArray(hTask, pxTaskStatusArray1, uxCurrentArraySize1)) {
            ESP_LOGW(TAG, "New task '%s' detected during measurement", pxTaskStatusArray2[i].pcTaskName);
        }
    }

    // Cleanup
    free(pxTaskStatusArray1);
    free(pxTaskStatusArray2);
}

