void AfeWakeWord::EncodeWakeWordData() {
    // Assuming the Opus encoder has been initialized elsewhere or initializing locally
    auto opus_encoder = std::make_unique<OpusEncoderWrapper>(16000, 1, OPUS_FRAME_DURATION_MS);
    opus_encoder->SetComplexity(0); // Minimal complexity for speed

    while (true) {
        std::unique_lock<std::mutex> lock(wake_word_mutex_);

        // Wait until there is at least one chunk of PCM data available
        wake_word_cv_.wait(lock, [this] { return !wake_word_pcm_.empty(); });

        // Retrieve the latest PCM data block
        auto pcm_data = std::move(wake_word_pcm_.front());
        wake_word_pcm_.pop_front();

        lock.unlock(); // Release lock early to avoid blocking other threads during encoding

        // Optional: Measure encoding time for debugging/profiling
#if CONFIG_ENABLE_ENCODING_PROFILING
        auto start_time = esp_timer_get_time();
#endif

        // Encode the PCM data to Opus
        std::vector<uint8_t> opus_packet;
        if (!opus_encoder->Encode(pcm_data, opus_packet)) {
            ESP_LOGW("AfeWakeWord", "Failed to encode PCM data to Opus");
            continue;
        }

#if CONFIG_ENABLE_ENCODING_PROFILING
        auto end_time = esp_timer_get_time();
        ESP_LOGD("AfeWakeWord", "Opus encoding took %lld us", end_time - start_time);
#endif

        // Push encoded packet to output queue
        {
            std::lock_guard<std::mutex> output_lock(wake_word_output_mutex_);
            wake_word_opus_.push_back(std::move(opus_packet));
        }
        wake_word_output_cv_.notify_one(); // Notify consumers waiting on encoded data
