        cJSON *threshold = cJSON_GetObjectItem(multinet_model, "threshold");
        cJSON *commands = cJSON_GetObjectItem(multinet_model, "commands");

        if (cJSON_IsString(language)) {
            language_ = language->valuestring;
        }
        if (cJSON_IsNumber(duration)) {
            duration_ = duration->valueint;
        }
        if (cJSON_IsNumber(threshold)) {
            threshold_ = threshold->valuedouble;
        }

        if (cJSON_IsArray(commands)) {
            for (int i = 0; i < cJSON_GetArraySize(commands); i++) {
                cJSON *command = cJSON_GetArrayItem(commands, i);
                if (cJSON_IsObject(command)) {
                    cJSON *command_name = cJSON_GetObjectItem(command, "command");
                    cJSON *text = cJSON_GetObjectItem(command, "text");
                    cJSON *action = cJSON_GetObjectItem(command, "action");

                    if (cJSON_IsString(command_name) &&
                        cJSON_IsString(text) &&
                        cJSON_IsString(action)) {

                        commands_.push_back({
                            command_name->valuestring,
                            text->valuestring,
                            action->valuestring
                        });

                        ESP_LOGI(TAG, "Command: %s, Text: %s, Action: %s",
                                 command_name->valuestring,
                                 text->valuestring,
                                 action->valuestring);
                    }
                }
            }
        }
    } else {
        ESP_LOGE(TAG, "No valid multinet_model found in index.json");
        cJSON_Delete(root);
        return false;
    }

    cJSON_Delete(root);

    // Step 2: Initialize Multinet Model
    const esp_mn_models_t *models = esp_mn_models_fetch();
    const char *wn_name = esp_mn_models_get_wakenet_name_by_lang(models, language_.c_str());

    if (wn_name == nullptr) {
        ESP_LOGE(TAG, "Unsupported language: %s", language_.c_str());
        return false;
    }

    multinet_ = esp_mn_handle_from_name(wn_name);
    if (multinet_ == nullptr) {
        ESP_LOGE(TAG, "Failed to load wakenet model for language: %s", language_.c_str());
        return false;
    }

    multinet_model_data_ = multinet_->create();
    if (multinet_model_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create wakenet model data");
        return false;
    }

    // Set detection threshold
    multinet_->set_det_threshold(multinet_model_data_, threshold_, 1);

    // Step 3: Initialize Audio Codec
    codec_ = codec;
    if (codec_ == nullptr) {
        ESP_LOGE(TAG, "Invalid AudioCodec pointer");
        return false;
    }

    if (!codec_->Configure(SAMPLING_RATE_HZ, INPUT_CHANNELS, OUTPUT_CHANNELS)) {
        ESP_LOGE(TAG, "Failed to configure audio codec");
        return false;
    }

    // Step 4: Allocate Memory for Task Stack in SPIRAM
    const size_t stack_size = 4096 * 7;
    if (wake_word_encode_task_stack_ == nullptr) {
        wake_word_encode_task_stack_ = (StackType_t *)heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM);
        assert(wake_word_encode_task_stack_ != nullptr);
    }

    if (wake_word_encode_task_buffer_ == nullptr) {
        wake_word_encode_task_buffer_ = (StaticTask_t *)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL);
        assert(wake_word_encode_task_buffer_ != nullptr);
    }

    // Step 5: Clear any previous buffered data
    wake_word_pcm_.clear();

    // All steps successful
    initialized_ = true;
    return true;
}

