#### 3. GPIO Control via External Expander (XL9555 Example)
Used for controlling external hardware such as camera power/reset lines through I²C expanders.

```cpp
class XL9555 : public I2cDevice
{
public:
    XL9555(i2c_master_bus_handle_t i2c_bus, uint8_t addr) : I2cDevice(i2c_bus, addr)
    {
        WriteReg(0x06, 0x03);  // Configure Port 0 direction
        WriteReg(0x07, 0xF0);  // Configure Port 1 direction
    }

    void SetOutputState(uint8_t bit, uint8_t level)
    {
        uint16_t data;
        int index = bit;

        if (bit < 8)
        {
            data = ReadReg(0x02);  // Read port 0 output register
        }
        else
        {
            data = ReadReg(0x03);  // Read port 1 output register
            index -= 8;
        }

        data = (data & ~(1 << index)) | (level << index);

        if (bit < 8)
        {
            WriteReg(0x02, data);
        }
        else
        {
            WriteReg(0x03, data);
        }
    }
};
```

This example shows interaction with a GPIO expander over I2C to control device states like camera reset or enable pins — useful when direct MCU GPIOs are limited.

