        }
    } else {
        // Calculate step for smooth transition
        int16_t diff = static_cast<int16_t>(target_brightness_) - static_cast<int16_t>(brightness_);
        uint32_t duration_ms = 500; // Example: 500ms transition
        uint32_t interval_ms = 20;  // Update every 20ms

        step_ = (diff != 0) ? (diff > 0 ? 1 : -1) : 0;
        if (step_ != 0 && abs(diff) > 1) {
            step_ = diff * interval_ms / duration_ms;
            if (step_ == 0) step_ = (diff > 0) ? 1 : -1;
