#include "esp_chip_info.h"
#include "esp_mac.h"
#include "esp_partition.h"
#include "esp_system.h"

std::string Board::GetSystemInfoJson() {
    cJSON *root = cJSON_CreateObject();

    // --- Hardware Info ---
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    const char* chip_model_str =
        chip_info.model == CHIP_ESP32 ? "ESP32" :
        chip_info.model == CHIP_ESP32S2 ? "ESP32-S2" :
        chip_info.model == CHIP_ESP32S3 ? "ESP32-S3" : "Unknown";
    cJSON_AddStringToObject(root, "chip_model", chip_model_str);
    cJSON_AddNumberToObject(root, "cpu_cores", chip_info.cores);
    cJSON_AddNumberToObject(root, "revision", chip_info.revision);

    // Flash size
    size_t flash_size_kb = 0;
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_APP, ESP_PARTITION_SUBTYPE_ANY, NULL);
    if (partition) {
        flash_size_kb = partition->size / 1024;
    }
    cJSON_AddNumberToObject(root, "flash_size_kb", flash_size_kb);

    // MAC Address
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    char macStr[18];
    snprintf(macStr, sizeof(macStr), "%02x:%02x:%02x:%02x:%02x:%02x",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    cJSON_AddStringToObject(root, "mac_address", macStr);

    // --- Application Metadata ---
    cJSON_AddStringToObject(root, "app_name", "XiaoZhi");
    cJSON_AddStringToObject(root, "version", "v1.0.0");
    cJSON_AddStringToObject(root, "compile_time", __DATE__ " " __TIME__);

    // --- Runtime Info ---
    cJSON_AddNumberToObject(root, "min_free_heap_bytes", esp_get_minimum_free_heap_size());

    // Generate UUID from MAC (simplified)
    std::string uuid = "uuid-" + std::string(macStr).substr(9);
    cJSON_AddStringToObject(root, "uuid", uuid.c_str());

    // Convert to string
    char *json_str = cJSON_PrintUnformatted(root);
    std::string result(json_str ? json_str : "{}");

    if (json_str) {
        free(json_str);
    }
    cJSON_Delete(root);

    return result;
}

