        std::lock_guard<std::mutex> lock(channel_mutex_);
        if (!udp_) {
            ESP_LOGE(TAG, "UDP channel not available");
            return;
        }

        try {
            // Prepare packet structure
            /*
             * UDP Encrypted OPUS Packet Format:
             * |type 1u|flags 1u|payload_len 2u|ssrc 4u|timestamp 4u|sequence 4u|
             * |nonce 16u|encrypted_payload payload_len-16|
             */

            uint16_t payload_len = packet->payload.size() + aes_nonce_.size();
            std::vector<uint8_t> buffer(sizeof(uint8_t) + sizeof(uint8_t) + sizeof(uint16_t) + 
                                       sizeof(uint32_t) + sizeof(uint32_t) + sizeof(uint32_t) + 
                                       payload_len);

            size_t offset = 0;

            // Type field
            buffer[offset++] = 0x02; // Audio packet type

            // Flags field
            buffer[offset++] = 0x00; // No special flags

            // Payload length (network byte order)
            uint16_t net_payload_len = htons(payload_len);
            memcpy(buffer.data() + offset, &net_payload_len, sizeof(uint16_t));
            offset += sizeof(uint16_t);

            // SSRC (network byte order)
            uint32_t net_ssrc = htonl(packet->ssrc);
            memcpy(buffer.data() + offset, &net_ssrc, sizeof(uint32_t));
            offset += sizeof(uint32_t);

            // Timestamp (network byte order)
            uint32_t net_timestamp = htonl(packet->timestamp);
            memcpy(buffer.data() + offset, &net_timestamp, sizeof(uint32_t));
            offset += sizeof(uint32_t);

