bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Step 1: Ensure WebSocket is connected
    if (!websocket_ || !websocket_->IsConnected()) {
        ESP_LOGW("WebsocketProtocol", "WebSocket not connected");
        return false;
    }

    // Step 2: Format the payload according to the protocol version
    std::vector<uint8_t> formatted_payload;

    if (version_ == 2) {
        // V2 format: [timestamp: uint64_t][size: uint32_t][data...]
        uint64_t timestamp = GetCurrentTimestamp();
        uint32_t payload_size = static_cast<uint32_t>(packet->data.size());

        formatted_payload.resize(sizeof(timestamp) + sizeof(payload_size) + payload_size);
        uint8_t* ptr = formatted_payload.data();

        memcpy(ptr, &timestamp, sizeof(timestamp));
        ptr += sizeof(timestamp);

        memcpy(ptr, &payload_size, sizeof(payload_size));
        ptr += sizeof(payload_size);

        memcpy(ptr, packet->data.data(), payload_size);
    } else if (version_ == 3) {
        // V3 format: [timestamp: varint][size: varint][data...]
        AppendVarInt(formatted_payload, GetCurrentTimestamp());
        AppendVarInt(formatted_payload, packet->data.size());
        formatted_payload.insert(formatted_payload.end(), packet->data.begin(), packet->data.end());
    } else {
        // Raw mode – no extra headers
        formatted_payload = std::move(packet->data);
    }

    // Step 3: Send the formatted payload via WebSocket
    if (!websocket_->SendBinary(formatted_payload.data(), formatted_payload.size())) {
        ESP_LOGE("WebsocketProtocol", "Failed to send audio packet");
        return false;
    }

    return true;
}

