    cJSON_AddNumberToObject(audio_params, "rate", 24000);         // Sample rate from ES8388
    cJSON_AddNumberToObject(audio_params, "channels", 1);        // Mono channel
    cJSON_AddNumberToObject(audio_params, "frame_duration", 60); // Opus frame duration

    cJSON_AddItemToObject(root, "audio_params", audio_params);

