void ParseServerHello(const cJSON* root) {
    if (root == nullptr) {
        ESP_LOGE(TAG, "Invalid JSON root in ParseServerHello");
        return;
    }

    // Validate message type
    auto type_item = cJSON_GetObjectItem(root, "type");
    if (!cJSON_IsString(type_item) || strcmp(type_item->valuestring, "hello") != 0) {
        ESP_LOGE(TAG, "Invalid or missing 'type' field in server hello");
        return;
    }

    // Get version
    auto version_item = cJSON_GetObjectItem(root, "version");
    if (!cJSON_IsString(version_item)) {
        ESP_LOGE(TAG, "Missing or invalid 'version' field in server hello");
        return;
    }
    strncpy(server_version_, version_item->valuestring, sizeof(server_version_) - 1);
    server_version_[sizeof(server_version_) - 1] = '\0';

    // Get transport method
    auto transport_item = cJSON_GetObjectItem(root, "transport");
    if (!cJSON_IsString(transport_item)) {
        ESP_LOGE(TAG, "Missing or invalid 'transport' field in server hello");
        return;
    }
    if (strcmp(transport_item->valuestring, "websocket") != 0) {
        ESP_LOGE(TAG, "Unsupported transport: %s", transport_item->valuestring);
        return;
    }

    // Parse audio_params
    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (!cJSON_IsObject(audio_params)) {
        ESP_LOGE(TAG, "Missing or invalid 'audio_params' object in server hello");
        return;
    }

    auto sample_rate_item = cJSON_GetObjectItem(audio_params, "sample_rate");
    if (!cJSON_IsNumber(sample_rate_item)) {
        ESP_LOGE(TAG, "Missing or invalid 'sample_rate' in audio_params");
        return;
    }
    sample_rate_ = sample_rate_item->valueint;

    auto frame_duration_item = cJSON_GetObjectItem(audio_params, "frame_duration");
    if (!cJSON_IsNumber(frame_duration_item)) {
        ESP_LOGE(TAG, "Missing or invalid 'frame_duration' in audio_params");
        return;
    }
    frame_duration_ms_ = frame_duration_item->valueint;

    // Signal that server hello was parsed successfully
    xEventGroupSetBits(event_group_handle_, WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT);

    ESP_LOGI(TAG, "Successfully parsed server hello: version=%s, sample_rate=%d, frame_duration=%d",
             server_version_, sample_rate_, frame_duration_ms_);
}
